#include <bits/stdc++.h>
using namespace std;
const int N=2e5+5;
struct Node{
    int val,id;
	long long ans;
}a[N];
bool cmp1(Node x,Node y){
    return x.val<y.val;
}
bool cmp2(Node x,Node y){
    return x.id<y.id;
}
int n,k;
int main(){
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i].val);
        a[i].id=i;
    }
    sort(a+1,a+n+1,cmp1);
    a[n].ans=0;
    for(int i=n-1;i;i--){
    	if(a[i].val==a[i+1].val)
    		a[i].ans=a[i+1].ans;
    	else
        	a[i].ans=max((long long)0,a[i+1].ans+1-(a[i+1].val-a[i].val-1)/k);
    }
    sort(a+1,a+n+1,cmp2);
    for(int i=1;i<=n;i++)
        printf("%lld ",a[i].ans);
    return 0;
}
